class SortAlgorithms : public TestWithParam<std::pair<std::string_view, std::initializer_list<uint>>> { };

TEST_P (SortAlgorithms, SortA) {
  std::vector vec  = GetParam( ).second;
  std::vector vec2 = GetParam( ).second;

  sort_a(vec.begin( ), vec.end( ));
  std::ranges::sort(vec2);

  EXPECT_EQ(vec, vec2);
}

